private boolean isFinallyBlockWithExit(Node n, int exitType, String labelName) {
  Node parent = n.getParent();
  return parent != null && parent.isTry() && NodeUtil.hasFinally(parent) && containsMatchingExitNode(n, exitType, labelName);
}

private boolean containsMatchingExitNode(Node n, int exitType, String labelName) {
  if (matchingExitNode(n, exitType, labelName)) {
    return true;
  }
  for (Node c = n.getFirstChild(); c != null; c = c.getNext()) {
    if (containsMatchingExitNode(c, exitType, labelName)) {
      return true;
    }
  }
  return false;
}

