private boolean containsExitNode(Node n) {
  if (n.isBlock()) {
    for (Node child : n.children()) {
      if (isExitNode(child)) {
        return true;
      }
    }
  }
  return isExitNode(n);
}

private boolean isExitNode(Node n) {
  return n.isReturn() || n.isBreak() || n.isContinue();
}

