private boolean containsCriticalExit(Node block, int exitType, String labelName) {
  for (Node c = block.getFirstChild(); c != null; c = c.getNext()) {
    if (matchingExitNode(c, exitType, labelName)) {
      return true;
    }
    if (c.isIf()) {
      if (containsCriticalExit(c.getFirstChild().getNext(), exitType, labelName)) {
        return true;
      }
      Node elseBlock = c.getFirstChild().getNext().getNext();
      if (elseBlock != null && containsCriticalExit(elseBlock, exitType, labelName)) {
        return true;
      }
    }
    if (c.isTry()) {
      if (containsCriticalExit(c.getFirstChild(), exitType, labelName)) {
        return true;
      }
      Node catchBlock = NodeUtil.getCatchBlock(c);
      if (NodeUtil.hasCatchHandler(catchBlock) && containsCriticalExit(catchBlock.getFirstChild().getLastChild(), exitType, labelName)) {
        return true;
      }
      Node finallyBlock = c.getLastChild();
      if (NodeUtil.hasFinally(c) && containsCriticalExit(finallyBlock, exitType, labelName)) {
        return true;
      }
    }
    if (c.isLabel() && containsCriticalExit(c.getLastChild(), exitType, labelName)) {
      return true;
    }
  }
  return false;
}

